mapper.select:
SELECT TAM.API_ID, TAM.API_NAME, TAM.SYSTEM_ID, TAM.API_URL, TAM.INTGR_INTERVAL, TAM.API_DESC, TAM.EXPIRD_TIME, TAM.UPDATE_TIME
,CASE WHEN EXEC_MODE_CD = 'B' THEN 'Batch' WHEN EXEC_MODE_CD = 'F' THEN 'SFTP' ELSE 'OnDemand' END AS EXEC_MODE_CD FROM DATAHUB.TB_API_MST TAM
WHERE 1=1
AND ( UPPER(TAM.API_NAME) LIKE '%' || UPPER(#{api_name}) || '%'
)
AND TAM.EXEC_MODE_CD IN
#{item}
AND TAM.API_URL IN
#{item}
GROUP BY TAM.API_ID, TAM.API_NAME, TAM.API_URL, TAM.INTGR_INTERVAL, TAM.API_DESC, TAM.EXPIRD_TIME, TAM.UPDATE_TIME, EXEC_MODE_CD

SELECT TAIPH.API_ID ,TAIPH.PROC_SERIAL , TAIPH.RESULT_CD , TAIPH.RESULT_MSG , TAIPH.RETRY_PROC , TAIPH.REQUEST_PARAM , TAM.API_NAME , TAM.API_URL , TAM.API_DESC , TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_TIME , TO_CHAR(TAM.UPDATE_TIME, 'YYYY-MM-DD HH24:MI:SS') as UPDATE_TIME , TISM.SYSTEM_NM , TAARH.API_URL as TARGETURL ,CASE WHEN EXEC_MODE_CD = 'B' THEN 'Batch' WHEN EXEC_MODE_CD = 'F' THEN 'SFTP' ELSE 'OnDemand' END AS EXEC_MODE_CD ,CASE WHEN RESULT_CD = 'S' THEN 'SUCCESS' ELSE 'FAIL' END AS RESULT_CD_DESC FROM DATAHUB.TB_API_INTRL_PROC_HIST TAIPH LEFT JOIN DATAHUB.TB_API_MST TAM ON TAM.API_ID = TAIPH.API_ID LEFT JOIN DATAHUB.TB_INTRL_SYSTEM_MST TISM ON TAM.SYSTEM_ID = TISM.SYSTEM_ID LEFT JOIN ( SELECT API_ID, API_URL FROM DATAHUB.TB_API_AUTH_REQ_HIST TAARH WHERE SYSTEM_ID IS NOT null and status_cd = 'GRANT' GROUP BY API_ID, API_URL ) TAARH ON TAARH.API_ID = TAIPH.API_ID WHERE 1=1
AND TAIPH.API_ID = #{api_id}
AND TAIPH.RESULT_CD = #{result_cd}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') >= #{start_date}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') <= #{end_date}

SELECT TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') AS CREATE_TIME, TAIPH.API_ID, TAM.API_NAME, TAM.API_URL, CASE WHEN TAM.EXEC_MODE_CD = 'O' THEN 'OnDemand' WHEN TAM.EXEC_MODE_CD = 'F' THEN 'SFTP' ELSE 'Batch' END AS EXEC_MODE_CD, COUNT(TAIPH.API_ID) AS PROC_COUNT, COALESCE(TAARH.SYSTEM_COUNT, 0) AS SYSTEM_COUNT FROM DATAHUB.TB_API_INTRL_PROC_HIST TAIPH INNER JOIN DATAHUB.TB_API_MST TAM ON TAIPH.API_ID = TAM.API_ID LEFT JOIN ( SELECT API_ID, API_URL, COUNT(CASE WHEN TAARH.STATUS_CD = 'GRANT' THEN taarh.SYSTEM_ID END) AS SYSTEM_COUNT FROM DATAHUB.TB_API_AUTH_REQ_HIST TAARH WHERE SYSTEM_ID IS NOT NULL AND STATUS_CD = 'GRANT' GROUP BY API_ID, API_URL ) TAARH ON TAARH.API_ID = TAIPH.API_ID WHERE 1=1
AND TAM.API_ID = #{api_id}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') >= #{start_date}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') <= #{end_date}
AND TAIPH.RESULT_CD = 'S' GROUP BY TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD'), TAIPH.API_ID, TAM.API_NAME, TAM.EXEC_MODE_CD, TAM.API_URL, TAARH.SYSTEM_COUNT

SELECT TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') AS CREATE_TIME, TAIPH.API_ID, TAM.API_NAME, TAM.API_URL, CASE WHEN TAM.EXEC_MODE_CD = 'O' THEN 'OnDemand' WHEN TAM.EXEC_MODE_CD = 'F' THEN 'SFTP' ELSE 'Batch' END AS EXEC_MODE_CD, COUNT(TAIPH.API_ID) AS PROC_COUNT, COALESCE(TAARH.SYSTEM_COUNT, 0) AS SYSTEM_COUNT FROM DATAHUB.TB_API_INTRL_PROC_HIST TAIPH INNER JOIN DATAHUB.TB_API_MST TAM ON TAIPH.API_ID = TAM.API_ID LEFT JOIN ( SELECT API_ID, API_URL, COUNT(CASE WHEN TAARH.STATUS_CD = 'GRANT' THEN taarh.SYSTEM_ID END) AS SYSTEM_COUNT FROM DATAHUB.TB_API_AUTH_REQ_HIST TAARH WHERE SYSTEM_ID IS NOT NULL AND STATUS_CD = 'GRANT' GROUP BY API_ID, API_URL ) TAARH ON TAARH.API_ID = TAIPH.API_ID WHERE 1=1
AND TAM.API_ID = #{api_id}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') >= #{start_date}
AND TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD') <= #{end_date}
AND TAIPH.RESULT_CD = 'F' GROUP BY TO_CHAR(TAIPH.CREATE_TIME, 'YYYY-MM-DD'), TAIPH.API_ID, TAM.API_NAME, TAM.EXEC_MODE_CD, TAM.API_URL, TAARH.SYSTEM_COUNT

SELECT TAARH.API_ID ,TAARH.HIST_SERIAL ,TAM.API_NAME ,TAM.API_URL ,TAM.REQ_PARAM ,TAARH.REG_USER ,TAARH.REFUSE_MSG ,TO_CHAR(TAARH.EXPIRD_DATE , 'YYYY-MM-DD HH24:MI:SS') AS EXPIRD_DATE ,TAARH.API_DESC ,TO_CHAR(TAARH.CREATE_TIME , 'YYYY-MM-DD HH24:MI:SS') AS CREATE_TIME ,TO_CHAR(TAARH.UPDATE_TIME , 'YYYY-MM-DD HH24:MI:SS') AS UPDATE_TIME ,TISM.SYSTEM_DESC ,TAARH.SYSTEM_ID ,TISM.API_KEY ,COALESCE(TAM.KONG_HOST, 'HOST_'|| TAM.API_ID) as KONG_HOST ,TISM.API_KEY AS KONG_KEY , CASE WHEN TAARH.STATUS_CD = 'APPLY' THEN '신청' WHEN TAARH.STATUS_CD = 'GRANT' THEN '승인' WHEN TAARH.STATUS_CD = 'REJECT' THEN '반려' ELSE '회수' END AS STATUS_CD ,CASE WHEN TAM.EXEC_MODE_CD = 'B' THEN 'Batch' WHEN TAM.EXEC_MODE_CD = 'F' THEN 'SFTP' ELSE 'OnDemand' END AS EXEC_MODE_CD ,ROW_NUMBER() OVER (ORDER BY TO_CHAR(TAARH.CREATE_TIME , 'YYYY-MM-DD HH24:MI:SS') DESC) as RANK ,TISM.SYSTEM_NM FROM DATAHUB.TB_API_AUTH_REQ_HIST TAARH LEFT JOIN DATAHUB.TB_API_MST TAM ON TAARH.API_ID = TAM.API_ID LEFT JOIN DATAHUB.TB_INTRL_SYSTEM_MST TISM ON TAARH.SYSTEM_ID = TISM.SYSTEM_ID WHERE TAM.EXEC_MODE_CD != 'F'
AND TAARH.API_ID = #{api_id}
AND TAARH.SYSTEM_ID = #{system_id}
AND UPPER(TAM.API_NAME) LIKE '%' || UPPER(#{api_name}) || '%'
AND TAM.API_NAME IN
#{item}
AND TAARH.STATUS_CD IN
#{item}
AND UPPER(TISM.SYSTEM_NM) LIKE '%' || UPPER(#{system_nm}) || '%'
AND TAM.EXEC_MODE_CD = #{exec_mode_cd}
AND TO_CHAR(TAARH.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') >= #{start_create_time}
AND TO_CHAR(TAARH.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') <= #{end_create_time}
AND TO_CHAR(TAARH.EXPIRD_DATE, 'YYYY-MM-DD HH24:MI:SS') >= #{start_expird_date}
AND TO_CHAR(TAARH.EXPIRD_DATE, 'YYYY-MM-DD HH24:MI:SS') <= #{end_expird_date}

mapper.insert:
INSERT INTO DATAHUB.TB_API_AUTH_REQ_HIST   
(
    API_ID
    ,STATUS_CD
    ,API_DESC
    ,REG_USER
    ,EXPIRD_DATE
    ,CREATE_TIME
    ,UPDATE_TIME
    ,SYSTEM_ID
    ,API_URL
) 
VALUES
(
     #{api_id}
    , #{status_cd}
    , #{api_desc}
    , #{reg_user}
    , TO_DATE( #{expird_date},'YYYY-MM-DD HH24:MI:SS')
    ,TO_TIMESTAMP(TO_CHAR(CURRENT_TIMESTAMP, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS')
    ,TO_TIMESTAMP(TO_CHAR(CURRENT_TIMESTAMP, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS')
    , #{system_id}
    , #{api_url}
)

mapper.select:
SELECT  STATUS_CD,
        API_DESC,
        API_ID,
        SYSTEM_ID,
        EXPIRD_DATE
FROM    DATAHUB.TB_API_AUTH_REQ_HIST
WHERE   1=1

        AND STATUS_CD = #{status_cd}


        AND API_ID = #{api_id}


        AND SYSTEM_ID = #{system_id}

SELECT METADATA_SEQ ,TDM.TABLE_NM ,TDM.COLUMN_NM ,TDM.DATA_TYPE ,TDM.METADATA_DESC ,TDM.UPDATE_USER ,TO_CHAR(TDM.CREATE_TIME , 'YYYY-MM-DD HH24:MI:SS') AS CREATE_TIME ,TO_CHAR(TDM.UPDATE_TIME , 'YYYY-MM-DD HH24:MI:SS') AS UPDATE_TIME FROM DATAHUB.TB_METADATA_MST TDM WHERE 1=1
AND TABLE_NM = #{table_nm}
AND UPPER(TDM.TABLE_NM) LIKE '%' || UPPER(#{table_nm}) || '%'
AND UPPER(TDM.COLUMN_NM) LIKE '%' || UPPER(#{column_nm}) || '%'
AND UPPER(TDM.METADATA_DESC) LIKE '%' || UPPER(#{metadata_desc}) || '%'
AND TO_CHAR(TDM.UPDATE_TIME, 'YYYY-MM-DD HH24:MI:SS') >= #{start_date}
AND TO_CHAR(TDM.UPDATE_TIME, 'YYYY-MM-DD HH24:MI:SS') <= #{end_date}

mapper.insert:
INSERT INTO DATAHUB.TB_METADATA_MST
(
    METADATA_SEQ
    ,TABLE_NM
    ,COLUMN_NM
    ,DATA_TYPE
    ,CREATE_TIME
    ,UPDATE_TIME
    ,METADATA_DESC
    ,UPDATE_USER
)
VALUES 
(
    NEXTVAL('DATAHUB.SEQ_TB_METADATA_MST') 
    ,#{table_nm}
    ,#{column_nm}
    ,#{data_type}
    , NOW()
    , NOW()
    ,#{metadata_desc}
    ,#{update_user}
)

mapper.update:
UPDATE DATAHUB.TB_METADATA_MST

    ,TABLE_NM = #{table_nm}
    ,COLUMN_NM = #{column_nm}
    ,DATA_TYPE = #{data_type}
    ,UPDATE_TIME = TO_DATE( #{update_time},'YYYY-MM-DD HH24:MI:SS')
    ,METADATA_DESC = #{metadata_desc}

WHERE 
    METADATA_SEQ = #{metadata_seq}

UPDATE DATAHUB.TB_INTRL_SYSTEM_MST

    SYSTEM_NM = #{system_nm}


    ,SYSTEM_DESC = #{system_desc}
    ,UPDATE_TIME = now()

WHERE SYSTEM_ID = #{system_id}

mapper.delete:
DELETE FROM DATAHUB.TB_INTRL_SYSTEM_MST TISM
WHERE 
    SYSTEM_ID = #{system_id}

mapper.select:
WITH TEMP AS ( SELECT 'TB_AL_CURRENT_DTL' || (1 + ((systemnum - 1) % 10)) AS TABLE, 'AL_SRL_NUM' || (1 + ((systemnum - 1) % 10)) AS category, CASE WHEN random() < 0.5 THEN 'On-demand' ELSE 'batch' END AS "type", '설명' AS ex, TO_CHAR(NOW(), 'YYYY-MM-DD HH24:MI:SS') AS collectionTime, systemnum AS systemnum FROM generate_series(1, 100) AS sequential_nums(systemnum) )
SELECT * FROM TEMP
WHERE "TABLE" = ${table}

mapper.delete:
DELETE FROM DATAHUB.TB_API_COL_MST
WHERE 1=1

    AND API_ID = #{api_id}


    AND TABLE_NM = #{table_nm}


    AND COLUMN_NM = #{column_nm}


    AND DATA_TYPE = #{data_type}

mapper.select:
SELECT ORG_ID AS ORGSCODE, ORG_NM AS ORGNAME
FROM ndhub.VW_ORG_MST
WHERE HIGHER_ORG_ID = #{ORGSCODE}

SELECT DISTINCT ORGSCODE, ORGNAME
FROM ndhub.TB_OFFICEROLE OFR 
INNER JOIN ndhub.TB_ORG ORG ON ORG.ORGSCODE = OFR.MGMTORGSCODE
WHERE 1=1
    AND OFR.HEADORGSCODE = #{HEADORGSCODE} 
    AND OFR.CSCENTERCODE = #{CSCENTERCODE}

SELECT DISTINCT OFF.OFFICESCODE, OFF.OFFICENAME
FROM ndhub.TB_OFFICEROLE OFR
INNER JOIN ndhub.TB_OFFICE OFF ON OFF.OFFICESCODE = OFR.OFFICESCODE
    WHERE 1=1
    AND OFR.HEADORGSCODE = #{HEADORGSCODE} 
    AND OFR.CSCENTERCODE = #{CSCENTERCODE} 
    AND OFR.MGMTORGSCODE = #{MGMTORGSCODE}

SELECT ROW_NUMBER() OVER(ORDER BY NE.NECATSEQ) ORDER_NUM , TOFF.OFFICE_ABBR_NM OFFICESCODE , TOFF.OFFICE_ID OFFICENAMESCODE , CLSCODE.NEMAINCLSCODE , CLSCODE.MAINDESCRIPTION , CLSCODE.NESUBCLSCODE , CLSCODE.SUBDESCRIPTION , USG.DESCRIPTION DESCRIPTION , NEC.MODELNAME , NE.NEALIAS2 , NE.NESCODE , NE.NEALIAS , TOFF.OFFICE_NM OFFICENAME , ADDR.addr1||' '||ADDR.addr2||' '||ADDR.addr3||' '|| CASE WHEN BLDG.addrnum <> '0' THEN BLDG.addrnum||'번지' ELSE '' END || CASE WHEN BLDG.addrsubnum <> '0' THEN BLDG.addrsubnum||'호' ELSE '' END AS FULL_ADDRESS , BLDG.BLDGSCODE , BLDG.BLDGNAME , NESU.NEA_NES_CNT , NESU.NEA_LINE_CNT , NESU.NEA_SVC_CNT , NESU.NEA_RELATION_NES_CNT , NESU.NEA_RELATION_LINE_CNT , NESU.NEA_RELATION_SVC_CNT FROM ndhub.TB_NE NE INNER JOIN ndhub.TB_NECAT NEC ON NEC.NECATSEQ = NE.NECATSEQ INNER JOIN ndhub.TB_NECLSCODE CLSCODE ON NE.MAINCLSCODE = CLSCODE.NEMAINCLSCODE AND NE.SUBCLSCODE = CLSCODE.NESUBCLSCODE INNER JOIN ndhub.TB_NEUSGCODE USG ON USG.svcnetcode = NE.svcnetcode and USG.neusgcode = ne.neusgcode LEFT OUTER JOIN ndhub.TB_OFFICE_MST TOFF ON TOFF.office_id = NE.officescode LEFT OUTER JOIN ndhub.tb_office_org_mapp_mst TOOMM on ne.svcnetcode= TOOMM.svc_net_cd and TOFF.office_id = toomm.office_id LEFT OUTER JOIN ndhub.VW_ORG_MST VOM5 on TOOMM.ORG_ID = VOM5.ORG_ID LEFT OUTER JOIN ndhub.VW_ORG_MST VOM4 on VOM4.ORG_ID = VOM5.HIGHER_ORG_ID LEFT OUTER JOIN ndhub.VW_ORG_MST VOM3 on VOM3.ORG_ID = VOM4.HIGHER_ORG_ID LEFT OUTER JOIN ndhub.TB_ADDR ADDR on ADDR.addrseq = NE.addrseq LEFT OUTER JOIN ndhub.TB_BLDG BLDG ON BLDG.BLDGSCODE = NE.BLDGSCODE LEFT OUTER JOIN ndhub.TB_NEA_NESUIDATA NESU on NESU.NESCODE = NE.NESCODE WHERE 1=1
AND ( NE.NEALIAS LIKE '%' || #{SEARCHTEXT} || '%' OR NE.NESCODE = #{SEARCHTEXT} )
AND VOM3.ORG_ID = #{HEADORGSCODE}
AND VOM4.ORG_ID = #{CSCENTERCODE}
AND VOM3.ORG_ID = #{MGMTORGSCODE}
AND TOFF.OFFICE_ID = #{OFFICESCODE}
ORDER BY NE.NECATSEQ
